1	//! R3 — restriction & lemma wrappers around `crate::formula::doc`.
2	//!
3	//! Byte shapes (probe provenance in workspace/BEHAVIOR.md "Restriction
4	//! blocks" / "Lemma blocks"):
5	//!
6	//! ```text
7	//! restriction Name:
8	//!   "formula"
9	//!   // safety formula          (iff the formula classifies safety)
10	//! <blank>
11	//!   /*
12	//!   expanded formula:
13	//!   "formula"
14	//!   */
15	//! ```
16	//!
17	//! ```text
18	//! lemma Name [attr1, attr2]:
19	//!   all-traces|exists-trace "formula"     (two lines when it overflows)
20	//! /*
21	//! guarded formula characterizing all counter-examples:   (| satisfying traces)
22	//! "<guarded block — opaque input>"
23	//! */
24	//! by sorry                                (| the embedded proof, verbatim)
25	//! ```
26	
27	use crate::ast::{Guarded, Lemma, LemmaAttr, Restriction, TraceQuantifier};
28	use crate::doc::{
29	    above_op, above_plus, beside_op, fsep, nest, punctuate, render_with, sep, text, vcat, Doc,
30	};
31	use crate::formula;
32	use crate::term::{RIBBON, WIDTH};
33	
34	/// One whole restriction block (also the echo of legacy `axiom` items —
35	/// probe:q_ax1).
36	pub fn render_restriction(r: &Restriction) -> String {
37	    render_with(WIDTH, RIBBON, &restriction_doc(r))
38	}
39	
40	/// One whole lemma block: header, quantifier/statement, guarded-formula
41	/// comment (skipped when `guarded` is `None`), and the proof tail
42	/// (`by sorry` when the lemma carries no embedded proof).
43	pub fn render_lemma(l: &Lemma, guarded: Option<&Guarded>) -> String {
44	    render_with(WIDTH, RIBBON, &lemma_doc(l, guarded))
45	}
46	
47	/// `"formula"` — the quotes attach directly around the formula doc; interior
48	/// breaks land one column past the opening quote's nesting (probe:q_l2).
49	fn quoted_formula(f: &crate::ast::Formula) -> Doc {
50	    beside_op(
51	        beside_op(crate::doc::char('"'), formula::doc(f)),
52	        crate::doc::char('"'),
53	    )
54	}
55	
56	/// A verbatim multi-line input block (guarded content, embedded proofs):
57	/// one `text` line per input line, stacked at the current nesting.
58	fn verbatim_doc(s: &str) -> Doc {
59	    vcat(s.lines().map(text).collect())
60	}
61	
62	// ── restrictions ────────────────────────────────────────────────────────────
63	
64	fn restriction_doc(r: &Restriction) -> Doc {
65	    let mut d = above_op(
66	        text(&format!("restriction {}:", r.name)),
67	        nest(2, &quoted_formula(&r.formula)),
68	    );
69	    if formula::is_safety(&r.formula) {
70	        d = above_op(d, nest(2, &text("// safety formula")));
71	    }
72	    // One blank line, then the expanded-formula comment at col 2. The
73	    // expanded content is byte-identical to the statement in every
74	    // observation (probes q_w1/q_pred1: predicate expansion happens upstream
75	    // of BOTH renderings), so the same formula renders twice.
76	    d = above_plus(d, text(""));
77	    let comment = above_op(
78	        above_op(
79	            above_op(text("/*"), text("expanded formula:")),
80	            quoted_formula(&r.formula),
81	        ),
82	        text("*/"),
83	    );
84	    above_plus(d, nest(2, &comment))
85	}
86	
87	// ── lemmas ──────────────────────────────────────────────────────────────────
88	
89	fn lemma_doc(l: &Lemma, guarded: Option<&Guarded>) -> Doc {
90	    let mut d = above_op(header_doc(l), nest(2, &statement_doc(l)));
91	    if let Some(g) = guarded {
92	        d = above_op(d, guarded_comment_doc(l.trace_quantifier, g));
93	    }
94	    let tail = match &l.proof {
95	        None => text("by sorry"),
96	        Some(p) => verbatim_doc(p),
97	    };
98	    above_op(d, tail)
99	}
100	
101	/// `lemma Name:` or `lemma Name [attrs]:` — a space before the `[`, the
102	/// attribute list fill-wrapped aligned after it with `]:` attached to the
103	/// last item (targets 5G_AKA sqn_ue_nodecrease / sqn_ue_unique); attributes
104	/// keep source order and duplicates (probe:q_la1).
105	fn header_doc(l: &Lemma) -> Doc {
106	    if l.attributes.is_empty() {
107	        return text(&format!("lemma {}:", l.name));
108	    }
109	    let items: Vec<Doc> = l.attributes.iter().map(|a| text(&attr_str(a))).collect();
110	    beside_op(
111	        beside_op(
112	            text(&format!("lemma {} [", l.name)),
113	            fsep(punctuate(&crate::doc::char(','), items)),
114	        ),
115	        text("]:"),
116	    )
117	}
118	
119	fn attr_str(a: &LemmaAttr) -> String {
120	    match a {
121	        LemmaAttr::Sources => "sources".into(),
122	        LemmaAttr::Reuse => "reuse".into(),
123	        LemmaAttr::UseInduction => "use_induction".into(),
124	        LemmaAttr::HideLemma(n) => format!("hide_lemma={n}"),
125	        LemmaAttr::Heuristic(v) => format!("heuristic={v}"),
126	    }
127	}
128	
129	/// `all-traces "…"` / `exists-trace "…"` at nest 2 — one line when the whole
130	/// statement fits, otherwise the keyword alone with the quoted formula below
131	/// at the same column (probe:q_w1; target:Minimal_Loop one-line cases).
132	fn statement_doc(l: &Lemma) -> Doc {
133	    let kw = match l.trace_quantifier {
134	        TraceQuantifier::AllTraces => "all-traces",
135	        TraceQuantifier::ExistsTrace => "exists-trace",
136	    };
137	    sep(vec![text(kw), quoted_formula(&l.formula)])
138	}
139	
140	/// The guarded-formula comment at column 0. Header text keyed by the trace
141	/// quantifier; content is opaque pre-computed input (probe:q_w1). Failed
142	/// conversions get the alternate header with the error text indented 2
143	/// (probe:q_r1 vs. the transform's raw error spelling).
144	fn guarded_comment_doc(tq: TraceQuantifier, g: &Guarded) -> Doc {
145	    let body = match g {
146	        Guarded::Formula(content) => {
147	            let header = match tq {
148	                TraceQuantifier::AllTraces => {
149	                    "guarded formula characterizing all counter-examples:"
150	                }
151	                TraceQuantifier::ExistsTrace => {
152	                    "guarded formula characterizing all satisfying traces:"
153	                }
154	            };
155	            above_op(text(header), verbatim_doc(content))
156	        }
157	        Guarded::Failed(err) => {
158	            let indented: Vec<Doc> = err
159	                .lines()
160	                .map(|ln| {
161	                    if ln.is_empty() {
162	                        text("")
163	                    } else {
164	                        text(&format!("  {ln}"))
165	                    }
166	                })
167	                .collect();
168	            above_op(text("conversion to guarded formula failed:"), vcat(indented))
169	        }
170	    };
171	    above_op(above_op(text("/*"), body), text("*/"))
172	}
