497	// ---------------------------------------------------------------------------
498	// List versions: hcat / hsep / vcat  (via reduceHoriz/reduceVert)
499	
500	#[derive(Clone, Copy)]
501	enum IsEmpty {
502	    // `Empty` mirrors the Haskell `reduceHoriz`/`reduceVert` return type; this
503	    // strict port only ever yields `NotEmpty`, but the variant is kept to match
504	    // the sanctioned source's shape.
505	    #[allow(dead_code)]
506	    Empty,
507	    NotEmpty,
508	}
509	
510	// `reduce_horiz`/`reduce_vert` fold a right-nested `Beside`/`Above` spine (the
511	// list built by `hcat`/`hsep`/`vcat`) into reduced form. That spine is as long
512	// as the list — thousands of rows for a huge `variants (modulo AC)` block — so
513	// both walk the spine iteratively onto a heap `Vec` and fold it back with
514	// `eliminate_empty`, exactly as the recursive form did, off the call stack.
515	// The left component of each spine node (`p`) is a single list item and is
516	// reduced recursively (bounded by that item's own depth).
517	
518	// The `loop { let next = match &cur {…}; cur = next }` idiom cannot become a
519	// `while let` here: the arm reassigns `cur`, which is still borrowed by the
520	// `while let` scrutinee.
521	#[allow(clippy::while_let_loop)]
522	fn reduce_horiz(d: &Doc) -> (IsEmpty, Doc) {
523	    let mut lefts: Vec<(Doc, bool)> = Vec::new();
524	    let mut cur = d.clone();
525	    loop {
526	        let next = match &cur {
527	            Beside(p, g, q) => {
528	                let (_, pr) = reduce_horiz(p);
529	                lefts.push((pr, *g));
530	                (**q).clone()
531	            }
532	            _ => break,
533	        };
534	        cur = next;
535	    }
536	    let mut acc = (IsEmpty::NotEmpty, cur);
537	    for (pr, g) in lefts.into_iter().rev() {
538	        acc = eliminate_empty(true, pr, g, acc);
539	    }
540	    acc
541	}
542	
543	#[allow(clippy::while_let_loop)] // see `reduce_horiz`: the arm reassigns `cur`.
544	fn reduce_vert(d: &Doc) -> (IsEmpty, Doc) {
545	    let mut lefts: Vec<(Doc, bool)> = Vec::new();
546	    let mut cur = d.clone();
547	    loop {
548	        let next = match &cur {
549	            Above(p, g, q) => {
550	                let (_, pr) = reduce_vert(p);
551	                lefts.push((pr, *g));
552	                (**q).clone()
553	            }
554	            _ => break,
555	        };
556	        cur = next;
557	    }
558	    let mut acc = (IsEmpty::NotEmpty, cur);
559	    for (pr, g) in lefts.into_iter().rev() {
560	        acc = eliminate_empty(false, pr, g, acc);
561	    }
562	    acc
563	}
564	
565	/// `beside_cons` = true builds `Beside`, false builds `Above`.
566	fn eliminate_empty(beside_cons: bool, p: Doc, g: bool, q: (IsEmpty, Doc)) -> (IsEmpty, Doc) {
567	    match p {
568	        Empty => q,
569	        _ => {
570	            let out = match q {
571	                (IsEmpty::NotEmpty, q1) => {
572	                    if beside_cons {
573	                        Beside(rc(p), g, rc(q1))
574	                    } else {
575	                        Above(rc(p), g, rc(q1))
576	                    }
577	                }
578	                (IsEmpty::Empty, _) => p,
579	            };
580	            (IsEmpty::NotEmpty, out)
581	        }
582	    }
583	}
584	
585	/// `hcat` — list version of `<>`.
586	pub fn hcat(ds: Vec<Doc>) -> Doc {
587	    let folded = ds
588	        .into_iter()
589	        .rev()
590	        .fold(Empty, |q, p| Beside(rc(p), false, rc(q)));
591	    reduce_horiz(&folded).1
592	}
593	
594	/// `hsep` — list version of `<+>`.
595	pub fn hsep(ds: Vec<Doc>) -> Doc {
596	    let folded = ds
597	        .into_iter()
598	        .rev()
599	        .fold(Empty, |q, p| Beside(rc(p), true, rc(q)));
600	    reduce_horiz(&folded).1
601	}
602	
603	/// `vcat` — list version of `$$`.
604	pub fn vcat(ds: Vec<Doc>) -> Doc {
605	    let folded = ds
606	        .into_iter()
607	        .rev()
608	        .fold(Empty, |q, p| Above(rc(p), false, rc(q)));
609	    reduce_vert(&folded).1
610	}
611	
612	/// `hang d1 n d2 = sep [d1, nest n d2]`.
613	pub fn hang(d1: Doc, n: isize, d2: Doc) -> Doc {
614	    sep(vec![d1, nest(n, &d2)])
615	}
616	
617	/// `punctuate p [d1,…,dn] = [d1<>p, …, d(n-1)<>p, dn]`.
618	pub fn punctuate(p: &Doc, ds: Vec<Doc>) -> Vec<Doc> {
619	    let n = ds.len();
620	    ds.into_iter()
621	        .enumerate()
622	        .map(|(i, d)| {
623	            if i + 1 < n {
624	                beside_op(d, p.clone())
625	            } else {
626	                d
627	            }
628	        })
629	        .collect()
630	}
