632	// ---------------------------------------------------------------------------
633	// sep / cat
634	
635	/// `sep` — either `hsep` (one line) or `vcat`.
636	pub fn sep(ds: Vec<Doc>) -> Doc {
637	    sep_x(true, ds)
638	}
639	
640	/// `cat` — either `hcat` (one line) or `vcat`.
641	pub fn cat(ds: Vec<Doc>) -> Doc {
642	    sep_x(false, ds)
643	}
644	
645	fn sep_x(x: bool, ds: Vec<Doc>) -> Doc {
646	    if ds.is_empty() {
647	        return Empty;
648	    }
649	    let mut it = ds.into_iter();
650	    let p = it.next().unwrap();
651	    let ys: Vec<Doc> = it.collect();
652	    sep1(x, &reduce_doc(&p), 0, &ys)
653	}
654	
655	fn sep1(g: bool, p: &Doc, k: isize, ys: &[Doc]) -> Doc {
656	    let pf = force(p);
657	    match &pf {
658	        NoDoc => NoDoc,
659	        Union(p1, q) => {
660	            let (p1, q) = (p1.clone(), q.clone());
661	            let (ya, yb) = (ys.to_vec(), ys.to_vec());
662	            union_(
663	                rc(lazy(move || sep1(g, &p1, k, &ya))),
664	                rc(lazy(move || {
665	                    above_nest(&q, false, k, &reduce_doc(&vcat(yb)))
666	                })),
667	            )
668	        }
669	        Empty => mk_nest(k, &sep_x(g, ys.to_vec())),
670	        Nest(n, p1) => {
671	            let (n, p1, ys) = (*n, p1.clone(), ys.to_vec());
672	            nest_(n, rc(lazy(move || sep1(g, &p1, k - n, &ys))))
673	        }
674	        NilAbove(p1) => {
675	            let (p1, ys) = (p1.clone(), ys.to_vec());
676	            nil_above_(rc(lazy(move || {
677	                above_nest(&p1, false, k, &reduce_doc(&vcat(ys)))
678	            })))
679	        }
680	        TextBeside(s, l, p1) => {
681	            let li = *l as isize;
682	            let (p1, ys) = (p1.clone(), ys.to_vec());
683	            text_beside_(
684	                s.clone(),
685	                *l,
686	                rc(lazy(move || sep_nb(g, &p1, k - li, &ys))),
687	            )
688	        }
689	        Above(..) => panic!("sep1 Above"),
690	        Beside(..) => panic!("sep1 Beside"),
691	        Lazy(_) => unreachable!("sep1: forced doc"),
692	    }
693	}
694	
695	fn sep_nb(g: bool, p: &Doc, k: isize, ys: &[Doc]) -> Doc {
696	    let pf = force(p);
697	    match &pf {
698	        Nest(_, p1) => sep_nb(g, p1, k, ys),
699	        Empty => {
700	            let rest = if g {
701	                hsep(ys.to_vec())
702	            } else {
703	                hcat(ys.to_vec())
704	            };
705	            let left = one_liner(&nil_beside(g, &reduce_doc(&rest)));
706	            let (k1, ys1) = (k, ys.to_vec());
707	            let right = lazy(move || nil_above_nest(false, k1, &reduce_doc(&vcat(ys1))));
708	            mk_union(left, right)
709	        }
710	        _ => sep1(g, &pf, k, ys),
711	    }
712	}
