814	// Best layout: best / nicest / fits / oneLiner
815	
816	fn one_liner(d: &Doc) -> Doc {
817	    let df = force(d);
818	    match &df {
819	        NoDoc => NoDoc,
820	        Empty => Empty,
821	        NilAbove(_) => NoDoc,
822	        TextBeside(s, l, p) => {
823	            let p = p.clone();
824	            text_beside_(s.clone(), *l, rc(lazy(move || one_liner(&p))))
825	        }
826	        Nest(k, p) => {
827	            let (k, p) = (*k, p.clone());
828	            nest_(k, rc(lazy(move || one_liner(&p))))
829	        }
830	        Union(p, _) => one_liner(p),
831	        Above(..) => panic!("oneLiner Above"),
832	        Beside(..) => panic!("oneLiner Beside"),
833	        Lazy(_) => unreachable!("oneLiner: forced doc"),
834	    }
835	}
