837	/// `best w r doc` — resolve unions to a single layout for line width `w`,
838	/// ribbon width `r`. Mirrors the Haskell `best`/`nicest1` including its
839	/// laziness: the resolved document's tails are thunks, so `fits` (which only
840	/// inspects a candidate's *first line*) never forces a branch beyond that
841	/// line, and the right branch of a union is only resolved when the left's
842	/// first line does not fit.
843	fn best(w: isize, r: isize, d: &Doc) -> Doc {
844	    get(w, r, d)
845	}
846	
847	fn get(w: isize, r: isize, d: &Doc) -> Doc {
848	    let df = force(d);
849	    match &df {
850	        Empty => Empty,
851	        NoDoc => NoDoc,
852	        NilAbove(p) => {
853	            let p = p.clone();
854	            nil_above_(rc(lazy(move || get(w, r, &p))))
855	        }
856	        TextBeside(s, l, p) => {
857	            let (li, p) = (*l as isize, p.clone());
858	            text_beside_(s.clone(), *l, rc(lazy(move || get1(w, r, li, &p))))
859	        }
860	        Nest(k, p) => {
861	            let (k, p) = (*k, p.clone());
862	            nest_(k, rc(lazy(move || get(w - k, r, &p))))
863	        }
864	        Union(p, q) => nicest(w, r, p, q),
865	        Above(..) => panic!("best get Above"),
866	        Beside(..) => panic!("best get Beside"),
867	        Lazy(_) => unreachable!("get: forced doc"),
868	    }
869	}
870	
871	fn get1(w: isize, r: isize, sl: isize, d: &Doc) -> Doc {
872	    let df = force(d);
873	    match &df {
874	        Empty => Empty,
875	        NoDoc => NoDoc,
876	        NilAbove(p) => {
877	            let p = p.clone();
878	            nil_above_(rc(lazy(move || get(w - sl, r, &p))))
879	        }
880	        TextBeside(s, l, p) => {
881	            let (li, p) = (*l as isize, p.clone());
882	            text_beside_(
883	                s.clone(),
884	                *l,
885	                rc(lazy(move || get1(w, r, sl + li, &p))),
886	            )
887	        }
888	        Nest(_, p) => get1(w, r, sl, p),
889	        Union(p, q) => nicest1(w, r, sl, p, q),
890	        Above(..) => panic!("best get1 Above"),
891	        Beside(..) => panic!("best get1 Beside"),
892	        Lazy(_) => unreachable!("get1: forced doc"),
893	    }
894	}
895	
896	fn nicest(w: isize, r: isize, p: &Doc, q: &Doc) -> Doc {
897	    nicest1(w, r, 0, p, q)
898	}
899	
900	fn nicest1(w: isize, r: isize, sl: isize, p: &Doc, q: &Doc) -> Doc {
901	    // Resolve the left branch lazily; keep it iff its first line fits (`fits`
902	    // forces only that first line). Resolve the right branch only otherwise.
903	    let (pc, qc) = (p.clone(), q.clone());
904	    let lp = lazy(move || get1(w, r, sl, &pc));
905	    if fits(w.min(r) - sl, &lp) {
906	        lp
907	    } else {
908	        lazy(move || get1(w, r, sl, &qc))
909	    }
910	}
911	
912	/// True iff the *first line* of `d` fits in `n` columns. Forces only up to the
913	/// first line break of an already-`best`-resolved (thunked) document.
914	fn fits(n: isize, d: &Doc) -> bool {
915	    if n < 0 {
916	        return false;
917	    }
918	    match &force(d) {
919	        NoDoc => false,
920	        Empty => true,
921	        NilAbove(_) => true,
922	        TextBeside(_, l, p) => fits(n - *l as isize, p),
923	        Above(..) => panic!("fits Above"),
924	        Beside(..) => panic!("fits Beside"),
925	        Union(..) => panic!("fits Union"),
926	        Nest(..) => panic!("fits Nest"),
927	        Lazy(_) => unreachable!("fits: forced doc"),
928	    }
929	}
