941	
942	/// Banker's-rounding of `line_len / ribbons` to match Haskell `round`.
943	fn round_ribbon(line_len: isize, ribbons: f64) -> isize {
944	    let v = line_len as f64 / ribbons;
945	    let floor = v.floor();
946	    let diff = v - floor;
947	    let rounded = if (diff - 0.5).abs() < 1e-9 {
948	        // round half to even
949	        let f = floor as i64;
950	        if f % 2 == 0 {
951	            f
952	        } else {
953	            f + 1
954	        }
955	    } else {
956	        v.round() as i64
957	    };
958	    rounded as isize
959	}
960	
961	/// Render a document in `PageMode` at line length `line_len` and
962	/// `ribbons_per_line`, producing the plain string (newline-separated lines,
963	/// each continuation prefixed by its indentation spaces).
964	pub fn render_page(line_len: isize, ribbons_per_line: f64, doc: &Doc) -> String {
965	    let ribbon_len = round_ribbon(line_len, ribbons_per_line);
966	    let reduced = reduce_doc(doc);
967	    let best_doc = best(line_len, ribbon_len, &reduced);
968	    display_page(line_len, ribbon_len, &best_doc)
969	}
970	
971	/// Render in `PageMode` with an EXPLICIT ribbon width (columns), bypassing the
972	/// `ribbons_per_line` division. The theory echo renders at `render_with(110,
973	/// 73, doc)`.
974	pub fn render_with(line_len: isize, ribbon_len: isize, doc: &Doc) -> String {
975	    let reduced = reduce_doc(doc);
976	    let best_doc = best(line_len, ribbon_len, &reduced);
977	    display_page(line_len, ribbon_len, &best_doc)
978	}
979	
980	fn display_page(page_width: isize, ribbon_width: isize, doc: &Doc) -> String {
981	    let _gap = page_width - ribbon_width;
982	    let mut out = String::new();
983	    lay(&mut out, 0, doc);
984	    out
985	}
986	
987	/// Iterative rewrite of the mutually-recursive `lay`/`lay1`/`lay2`. The
988	/// display walk is tail-recursive and its depth follows the `NilAbove` chain,
989	/// which is as deep as the document has lines (thousands for a huge variant
990	/// block). `mid_line` mirrors which of `lay` (start-of-line: emit indent
991	/// before text, accumulate `Nest` into the indent) / `lay2` (mid-line: text
992	/// already indented, `Nest` values ignored) the recursive form was in. The
993	/// `k` threading, indentation, and text emission are byte-for-byte identical.
994	fn lay(out: &mut String, mut k: isize, d: &Doc) {
995	    // `Doc` implements `Drop`, so nodes are inspected by reference and the tail
996	    // re-`force`d rather than moved out.
997	    let mut cur = force(d);
998	    let mut mid_line = false;
999	    loop {
1000	        let next = if !mid_line {
1001	            match &cur {
1002	                Nest(k1, p) => {
1003	                    k += *k1;
1004	                    force(p)
1005	                }
1006	                Empty => return,
1007	                NilAbove(p) => {
1008	                    out.push('\n');
1009	                    force(p)
1010	                }
1011	                TextBeside(s, l, p) => {
1012	                    out.push_str(&indent(k));
1013	                    out.push_str(s);
1014	                    k += *l as isize;
1015	                    mid_line = true;
1016	                    force(p)
1017	                }
1018	                Above(..) => panic!("display lay Above"),
1019	                Beside(..) => panic!("display lay Beside"),
1020	                NoDoc => panic!("display lay NoDoc"),
1021	                Union(..) => panic!("display lay Union"),
1022	                Lazy(_) => unreachable!("lay: forced doc"),
1023	            }
1024	        } else {
1025	            match &cur {
1026	                NilAbove(p) => {
1027	                    out.push('\n');
1028	                    mid_line = false;
1029	                    force(p)
1030	                }
1031	                TextBeside(s, l, p) => {
1032	                    out.push_str(s);
1033	                    k += *l as isize;
1034	                    force(p)
1035	                }
1036	                Nest(_, p) => force(p),
1037	                Empty => return,
1038	                Above(..) => panic!("display lay2 Above"),
1039	                Beside(..) => panic!("display lay2 Beside"),
1040	                NoDoc => panic!("display lay2 NoDoc"),
1041	                Union(..) => panic!("display lay2 Union"),
1042	                Lazy(_) => unreachable!("lay2: forced doc"),
1043	            }
1044	        };
1045	        cur = next;
1046	    }
1047	}
1048	
