1	//! R2 — rule rendering: the whole rule block, byte-identical to the echo.
2	//!
3	//! Every layout decision is oracle-pinned (see workspace/BEHAVIOR.md "Rule
4	//! blocks" for probe provenance). Shape summary:
5	//!
6	//! ```text
7	//! rule (modulo E) Name[color=#abcdef, no_derivcheck, issapicrule,
8	//!                      role='r']:
9	//!    [ Prem( x ), !Persistent( y )[+, no_precomp] ]
10	//!   --[ Act( x ) ]->
11	//!    [ Concl( x ) ]
12	//!
13	//!   // loop breakers: [0,1]
14	//!   /* has exactly the trivial AC variant */
15	//! ```
16	//!
17	//! * body = `nest 3 (sep [prems, nest (-1) arrow, concls])` — one line when
18	//!   it fits, otherwise premises/conclusions at indent 3 and the arrow row at
19	//!   indent 2;
20	//! * each bracket group = `sep ["[", fsep facts, "]"]` (`[ ]` when empty);
21	//!   the empty-action arrow is the literal `-->`;
22	//! * a fact = `sep [name<>"(" <+> fsep args, ")"]` (`Name( )` when nullary)
23	//!   with the annotation suffix attached after the `)`;
24	//! * the trailing comment is either the trivial-variant one-liner or the
25	//!   `/* rule (modulo AC) … variants (modulo AC) … */` block with numbered
26	//!   substitution groups: number right-aligned to the widest index, each
27	//!   substitution `lhs $$ nest 6 ("= " <> rhs)` — the HughesPJ overlap pads
28	//!   a short lhs to column 6 and pushes `= rhs` to its own line otherwise.
29	
30	use crate::ast::{AcVariants, Fact, FactAnnotation, Rule, RuleAttr, Term};
31	use crate::doc::{
32	    above_op, above_plus, beside_op, beside_space, char, fsep, nest, punctuate,
33	    render_with, sep, text, vcat, Doc,
34	};
35	use crate::term::{self, RIBBON, WIDTH};
36	
37	/// One fact: `Name( arg, … )`, persistent prefixed with `!`, annotations
38	/// attached after the closing paren.
39	pub fn render_fact(f: &Fact) -> String {
40	    render_with(WIDTH, RIBBON, &fact_doc(f))
41	}
42	
43	/// One whole rule block: header, body, blank line, loop-breaker annotation,
44	/// and the AC-variants comment (`None` → the trivial-variant one-liner).
45	pub fn render(rule: &Rule, variants: Option<&AcVariants>) -> String {
46	    render_with(WIDTH, RIBBON, &block_doc(rule, variants))
47	}
48	
49	fn block_doc(rule: &Rule, variants: Option<&AcVariants>) -> Doc {
50	    let mut d = core_doc(rule);
51	    // `$+$` below the blank line: `$$` overlap would otherwise pull the
52	    // nested comment line up onto it.
53	    d = above_plus(d, text(""));
54	    if let Some(lb) = breaker_doc(&rule.loop_breakers) {
55	        d = above_plus(d, nest(2, &lb));
56	    }
57	    above_plus(d, nest(2, &comment_doc(variants)))
58	}
59	
60	/// Header + body (shared by the toplevel block and the AC rule re-rendered
61	/// inside the variants comment).
62	fn core_doc(rule: &Rule) -> Doc {
63	    above_op(header_doc(rule), nest(3, &body_doc(rule)))
64	}
65	
66	// ── header ──────────────────────────────────────────────────────────────────
67	
68	/// `rule (modulo E) Name:`, with the rendered attribute list in `[…]` before
69	/// the colon; attributes fill-wrap aligned after the `[`
70	/// (target:issue713, probe:p_rattr).
71	fn header_doc(rule: &Rule) -> Doc {
72	    let mut head = String::from("rule ");
73	    if let Some(m) = &rule.modulo {
74	        head.push_str(&format!("(modulo {m}) "));
75	    }
76	    head.push_str(&rule.name);
77	    let attrs = attr_items(&rule.attributes);
78	    if attrs.is_empty() {
79	        text(&format!("{head}:"))
80	    } else {
81	        beside_op(
82	            beside_op(
83	                text(&format!("{head}[")),
84	                fsep(punctuate(
85	                    &char(','),
86	                    attrs.iter().map(|a| text(a)).collect(),
87	                )),
88	            ),
89	            text("]:"),
90	        )
91	    }
92	}
93	
94	/// Canonical attribute list: color, process, no_derivcheck, issapicrule, role
95	/// — the last color/process/role declaration wins; external attributes are
96	/// dropped (probe:p_rattr, target:issue713; target:ct pins the SAPIC
97	/// `process` attribute).
98	///
99	/// The SAPIC `process="…"` attribute (target:ct, probe:p_process) renders
100	/// DOUBLE-quoted (unlike `role='…'`), between `color` and `no_derivcheck`, and
101	/// carries the process snippet VERBATIM: no escaping is applied and none is
102	/// observable (its text uses single-quoted string constants — `'proofOfID'` —
103	/// so no `"`/`\` ever appears; spaces, commas, `<>`, `()`, `;` all sit inside
104	/// the quotes as one unbreakable text token). Absent when the rule is not
105	/// SAPIC-generated (no `RuleAttr::Process`).
106	fn attr_items(attrs: &[RuleAttr]) -> Vec<String> {
107	    let mut color = None;
108	    let mut process = None;
109	    let mut no_derivcheck = false;
110	    let mut issapicrule = false;
111	    let mut role = None;
112	    for a in attrs {
113	        match a {
114	            RuleAttr::Color(c) => color = Some(c.clone()),
115	            RuleAttr::Process(p) => process = Some(p.clone()),
116	            RuleAttr::NoDerivCheck => no_derivcheck = true,
117	            RuleAttr::IsSapicRule => issapicrule = true,
118	            RuleAttr::Role(r) => role = Some(r.clone()),
119	            RuleAttr::External(..) => {}
120	        }
121	    }
122	    let mut items = Vec::new();
123	    if let Some(c) = color {
124	        items.push(format!("color=#{c}"));
125	    }
126	    if let Some(p) = process {
127	        items.push(format!("process=\"{p}\""));
128	    }
129	    if no_derivcheck {
130	        items.push("no_derivcheck".into());
131	    }
132	    if issapicrule {
133	        items.push("issapicrule".into());
134	    }
135	    if let Some(r) = role {
136	        items.push(format!("role='{r}'"));
137	    }
138	    items
139	}
140	
141	// ── body ────────────────────────────────────────────────────────────────────
142	
143	/// `sep [prems, nest (-1) arrow, concls]` under the rule's nest 3: one line
144	/// `[ … ] --[ … ]-> [ … ]` when it fits, otherwise three rows with the arrow
145	/// out-dented one column (targets cav13/NSLPK3, probe:t_wide).
146	fn body_doc(rule: &Rule) -> Doc {
147	    sep(vec![
148	        fact_list_doc(&rule.premises),
149	        nest(-1, &arrow_doc(&rule.actions)),
150	        fact_list_doc(&rule.conclusions),
151	    ])
152	}
153	
154	/// `-->` when there are no actions, otherwise the `--[ … ]->` bracket group
155	/// (probe:p_arr1 rule AR pins the arrow to the SAME nested-sep construction
156	/// as the premise/conclusion lists: actions stay beside `--[` while `]->`
157	/// drops alone).
158	fn arrow_doc(actions: &[Fact]) -> Doc {
159	    if actions.is_empty() {
160	        text("-->")
161	    } else {
162	        bracket_group("--[", actions, "]->")
163	    }
164	}
165	
166	fn fact_list_doc(facts: &[Fact]) -> Doc {
167	    bracket_group("[", facts, "]")
168	}
169	
170	/// `sep [sep [open, fsep facts], close]` — a graded three-way layout
171	/// (probe:p_arr1; targets mesh ProvisionerWaitingUser vs DeviceWaitingUser,
172	/// NSLPK3 R_1/I_2, Tutorial Serv_1):
173	///   * everything on one line when `open facts close` fits (`[ f1, f2 ]`,
174	///     kept at exactly ribbon width — p_arr1 rule PR at 73);
175	///   * otherwise the closing bracket drops to the group's column; the
176	///     opening bracket keeps ALL the facts beside it iff they fit on that
177	///     line as a unit (mesh DeviceWaitingUser at exactly 73);
178	///   * otherwise the opening bracket is alone too and the facts fill-wrap
179	///     at the group's column between the brackets (NSLPK3 R_1: three facts
180	///     share a fill line; Serv_1: `--[` alone although the first action
181	///     would fit beside it).
182	fn bracket_group(open: &str, facts: &[Fact], close: &str) -> Doc {
183	    if facts.is_empty() {
184	        return sep(vec![text(open), text(close)]);
185	    }
186	    sep(vec![
187	        sep(vec![
188	            text(open),
189	            fsep(punctuate(&char(','), facts.iter().map(fact_doc).collect())),
190	        ]),
191	        text(close),
192	    ])
193	}
194	
195	// ── facts ───────────────────────────────────────────────────────────────────
196	
197	/// `Name( a, b )` — args fill-wrap aligned after `Name( `, the closing paren
198	/// drops to the fact's own column when the args are multi-line
199	/// (probe:t_wide); `Name( )` when nullary (target:mesh); `!` prefix for
200	/// persistent facts; annotation suffix attached directly after the paren.
201	/// Formula action atoms reuse this construction unchanged (probe:q_l3).
202	pub(crate) fn fact_doc(f: &Fact) -> Doc {
203	    let head = format!("{}{}(", if f.persistent { "!" } else { "" }, f.name);
204	    let core = if f.args.is_empty() {
205	        sep(vec![text(&head), char(')')])
206	    } else {
207	        sep(vec![
208	            beside_space(
209	                text(&head),
210	                fsep(punctuate(
211	                    &char(','),
212	                    f.args.iter().map(term::doc).collect(),
213	                )),
214	            ),
215	            char(')'),
216	        ])
217	    };
218	    match annotation_suffix(&f.annotations) {
219	        Some(s) => beside_op(core, text(&s)),
220	        None => core,
221	    }
222	}
223	
224	/// `[+, -, no_precomp]` in canonical order regardless of source order
225	/// (probe:p_fann `[no_precomp,+]` → `[+, no_precomp]`; target:seqdfsneeded
226	/// `[no_precomp,-]` → `[-, no_precomp]`).
227	fn annotation_suffix(annotations: &[FactAnnotation]) -> Option<String> {
228	    if annotations.is_empty() {
229	        return None;
230	    }
231	    let mut sorted: Vec<FactAnnotation> = annotations.to_vec();
232	    sorted.sort();
233	    sorted.dedup();
234	    let spellings: Vec<&str> = sorted
235	        .iter()
236	        .map(|a| match a {
237	            FactAnnotation::SolveFirst => "+",
238	            FactAnnotation::SolveLast => "-",
239	            FactAnnotation::NoSources => "no_precomp",
240	        })
241	        .collect();
242	    Some(format!("[{}]", spellings.join(", ")))
243	}
244	
245	// ── loop breakers ───────────────────────────────────────────────────────────
246	
247	/// `// loop breaker: [0]` / `// loop breakers: [0,1]` — plural iff several,
248	/// indices comma-separated without spaces (probes c_loop, p_lb2).
249	fn breaker_doc(indices: &[usize]) -> Option<Doc> {
250	    if indices.is_empty() {
251	        return None;
252	    }
253	    let list = indices
254	        .iter()
255	        .map(|i| i.to_string())
256	        .collect::<Vec<_>>()
257	        .join(",");
258	    let noun = if indices.len() == 1 {
259	        "loop breaker"
260	    } else {
261	        "loop breakers"
262	    };
263	    Some(text(&format!("// {noun}: [{list}]")))
264	}
265	
266	// ── the AC-variants comment ─────────────────────────────────────────────────
267	
268	/// `None` → the trivial one-liner; otherwise the comment block re-rendering
269	/// the AC rule, its numbered substitution groups, and its loop-breaker line
270	/// (probes p_var1, p_lbvar; targets cav13/Joux/CH07/mesh).
271	fn comment_doc(variants: Option<&AcVariants>) -> Doc {
272	    let Some(v) = variants else {
273	        return text("/* has exactly the trivial AC variant */");
274	    };
275	    let mut d = above_op(text("/*"), core_doc(&v.ac_rule));
276	    if !v.substitutions.is_empty() {
277	        d = above_op(d, nest(2, &substitutions_doc(&v.substitutions)));
278	    }
279	    if let Some(lb) = breaker_doc(&v.ac_rule.loop_breakers) {
280	        d = above_op(d, nest(2, &lb));
281	    }
282	    above_op(d, text("*/"))
283	}
284	
285	/// `variants (modulo AC)` and the numbered groups, separated by lines of
286	/// bare indent (four spaces at the observed nesting — probe:p_var1 byte
287	/// check); numbers right-aligned to the widest index (`  1.` … `160.` —
288	/// targets cav13 (1 digit), CH07 (2), Joux (3)).
289	fn substitutions_doc(groups: &[Vec<(Term, Term)>]) -> Doc {
290	    let width = groups.len().to_string().len();
291	    let mut rows = vec![text("variants (modulo AC)")];
292	    for (i, group) in groups.iter().enumerate() {
293	        if i > 0 {
294	            rows.push(text(""));
295	        }
296	        let prefix = format!("{:>width$}. ", i + 1);
297	        rows.push(beside_op(
298	            text(&prefix),
299	            vcat(group.iter().map(|(l, r)| substitution_doc(l, r)).collect()),
300	        ));
301	    }
302	    vcat(rows)
303	}
304	
305	/// One substitution: `lhs $$ nest 6 ("= " <> rhs)` — the overlap pads a
306	/// short lhs to column 6 (`~lv2  = ~lv2.4`) and drops `= rhs` to its own
307	/// line at column 6 when the lhs is 6 columns or wider (probe:p_var1
308	/// `~longvariablenameone`); the rhs is a full R1 term with its own wrapping
309	/// (target:mesh multi-line substitution values).
310	fn substitution_doc(lhs: &Term, rhs: &Term) -> Doc {
311	    above_op(
312	        term::doc(lhs),
313	        nest(6, &beside_op(text("= "), term::doc(rhs))),
314	    )
315	}
