1	//! R1 — signature block: `builtins:` / `functions:` / `equations:`.
2	//!
3	//! Renders the declared signature as the theory echo's first section,
4	//! performing the OBSERVABLE closure over builtins (all oracle-pinned; see
5	//! workspace/BEHAVIOR.md "Signature section" for probe provenance):
6	//!
7	//!   * only diffie-hellman / bilinear-pairing / multiset / natural-numbers /
8	//!     xor keep a `builtins:` entry, in exactly that canonical order;
9	//!     bilinear-pairing induces diffie-hellman; every other builtin expands
10	//!     into function/equation entries instead;
11	//!   * the base pairing symbols `fst/1, pair/2, snd/1` and the two projection
12	//!     equations are always present (`dest-pairing` flips fst/snd to
13	//!     `[destructor]`);
14	//!   * functions dedup and sort byte-wise; attributes render
15	//!     `[private,constructor]` / `[private,destructor]` / `[destructor]` /
16	//!     nothing;
17	//!   * equations dedup exactly and sort by STRUCTURAL term order on
18	//!     (lhs, rhs) — variables below applications, applications by head name
19	//!     then arguments, tuples as right-nested `pair` applications (probes
20	//!     p_eqA–p_eqI; NOT byte order of the rendered text — refuted by
21	//!     target:contract / target:mesh);
22	//!   * layout: builtins and functions are `text prefix <> fsep` fill lines;
23	//!     the equations block is all-or-nothing — one line when it fits the
24	//!     73-column ribbon, otherwise one equation per line at indent 4; an
25	//!     overlong equation drops `= rhs` to (equation indent − 2).
26	
27	use crate::ast::{Equation, FunctionDecl, Signature, SortHint, Term, VarSpec};
28	use crate::doc::{
29	    beside_op, char, fsep, nest, punctuate, render_with, sep, text, vcat, Doc,
30	};
31	use crate::term::{self, RIBBON, WIDTH};
32	use std::cmp::Ordering;
33	
34	/// Header comment above the declarations (byte-exact from every capture).
35	const HEADER: &str = "// Function signature and definition of the equational theory E";
36	
37	/// Full signature section: header comment, blank line, then the declaration
38	/// lines (`builtins:` only when it has surviving entries).
39	pub fn render(sig: &Signature) -> String {
40	    render_with(WIDTH, RIBBON, &block_doc(sig))
41	}
42	
43	pub(crate) fn block_doc(sig: &Signature) -> Doc {
44	    let mut lines = vec![text(HEADER), text("")];
45	    let builtin_names = builtins_line_entries(&sig.builtins);
46	    if !builtin_names.is_empty() {
47	        lines.push(fill_line(
48	            "builtins: ",
49	            builtin_names.iter().map(|n| text(n)).collect(),
50	        ));
51	    }
52	    lines.push(fill_line(
53	        "functions: ",
54	        merged_function_items(sig).iter().map(|s| text(s)).collect(),
55	    ));
56	    lines.push(equations_doc(sig));
57	    vcat(lines)
58	}
59	
60	/// `text prefix <> fsep (punctuate ',' items)`: comma attached to the
61	/// preceding item, fill space between items, continuation aligned after the
62	/// prefix (probe:b_all, probe:b_revealing-signing).
63	fn fill_line(prefix: &str, items: Vec<Doc>) -> Doc {
64	    beside_op(text(prefix), fsep(punctuate(&char(','), items)))
65	}
66	
67	// ── builtins line ───────────────────────────────────────────────────────────
68	
69	/// The five builtins with a line entry, in canonical order (probe:b_all).
70	const LINE_ORDER: [&str; 5] = [
71	    "diffie-hellman",
72	    "bilinear-pairing",
73	    "multiset",
74	    "natural-numbers",
75	    "xor",
76	];
77	
78	fn builtins_line_entries(declared: &[String]) -> Vec<&'static str> {
79	    let mut present = [false; 5];
80	    for b in declared {
81	        match b.as_str() {
82	            "diffie-hellman" => present[0] = true,
83	            // bilinear-pairing induces diffie-hellman (probe:b_bilinear-pairing).
84	            "bilinear-pairing" => {
85	                present[0] = true;
86	                present[1] = true;
87	            }
88	            "multiset" => present[2] = true,
89	            "natural-numbers" => present[3] = true,
90	            "xor" => present[4] = true,
91	            _ => {}
92	        }
93	    }
94	    LINE_ORDER
95	        .iter()
96	        .zip(present)
97	        .filter_map(|(n, p)| p.then_some(*n))
98	        .collect()
99	}
100	
101	// ── functions line ──────────────────────────────────────────────────────────
102	
103	fn decl(name: &str, arity: usize, private: bool, destructor: bool) -> FunctionDecl {
104	    FunctionDecl {
105	        name: name.into(),
106	        arity,
107	        private,
108	        destructor,
109	    }
110	}
111	
112	/// `name/arity` + attribute suffix (probe:f_attrs): `private` implies a
113	/// role keyword is shown too; a public destructor shows `[destructor]` alone;
114	/// a public constructor shows nothing.
115	fn function_item(d: &FunctionDecl) -> String {
116	    let mut s = format!("{}/{}", d.name, d.arity);
117	    if d.private || d.destructor {
118	        let mut attrs: Vec<&str> = Vec::new();
119	        if d.private {
120	            attrs.push("private");
121	        }
122	        attrs.push(if d.destructor { "destructor" } else { "constructor" });
123	        s.push('[');
124	        s.push_str(&attrs.join(","));
125	        s.push(']');
126	    }
127	    s
128	}
129	
130	/// Base + builtin-expansion + user function symbols, deduped and byte-sorted.
131	/// Sorting the full item text equals sorting by name (`/` orders below every
132	/// identifier character), matching probe:f_sort.
133	fn merged_function_items(sig: &Signature) -> Vec<String> {
134	    let mut decls: Vec<FunctionDecl> = base_functions(&sig.builtins);
135	    for b in &sig.builtins {
136	        decls.extend(builtin_functions(b));
137	    }
138	    decls.extend(sig.functions.iter().cloned());
139	    let mut items: Vec<String> = decls.iter().map(function_item).collect();
140	    items.sort();
141	    items.dedup();
142	    items
143	}
144	
145	/// Always-present pairing symbols; `dest-pairing` flips the projections to
146	/// destructors (probe:b_none, probe:b_dest-pairing).
147	fn base_functions(declared: &[String]) -> Vec<FunctionDecl> {
148	    let dest = declared.iter().any(|b| b == "dest-pairing");
149	    vec![
150	        decl("fst", 1, false, dest),
151	        decl("pair", 2, false, false),
152	        decl("snd", 1, false, dest),
153	    ]
154	}
155	
156	/// Function symbols induced by one declared builtin (probes:b_*; compatibility
157	/// content learned from oracle output).
158	fn builtin_functions(name: &str) -> Vec<FunctionDecl> {
159	    match name {
160	        "hashing" => vec![decl("h", 1, false, false)],
161	        "asymmetric-encryption" | "dest-asymmetric-encryption" => vec![
162	            decl("adec", 2, false, name.starts_with("dest-")),
163	            decl("aenc", 2, false, false),
164	            decl("pk", 1, false, false),
165	        ],
166	        "signing" | "dest-signing" => vec![
167	            decl("pk", 1, false, false),
168	            decl("sign", 2, false, false),
169	            decl("true", 0, false, false),
170	            decl("verify", 3, false, name.starts_with("dest-")),
171	        ],
172	        "symmetric-encryption" | "dest-symmetric-encryption" => vec![
173	            decl("sdec", 2, false, name.starts_with("dest-")),
174	            decl("senc", 2, false, false),
175	        ],
176	        "revealing-signing" => vec![
177	            decl("getMessage", 1, false, false),
178	            decl("pk", 1, false, false),
179	            decl("revealSign", 2, false, false),
180	            decl("revealVerify", 3, false, false),
181	            decl("true", 0, false, false),
182	        ],
183	        "locations-report" => vec![
184	            decl("check_rep", 2, false, true),
185	            decl("get_rep", 1, false, true),
186	            decl("rep", 2, true, false),
187	            decl("report", 1, false, false),
188	        ],
189	        _ => Vec::new(),
190	    }
191	}
192	
193	// ── equations block ─────────────────────────────────────────────────────────
194	
195	/// `sep (header : map (nest 4) (punctuate ',' eqs))`: one line when it fits,
196	/// otherwise header alone and one equation per line at indent 4
197	/// (probe:e_mid, probe:e_conv, target:Tutorial).
198	fn equations_doc(sig: &Signature) -> Doc {
199	    let header = if sig.convergent {
200	        "equations [convergent]:"
201	    } else {
202	        "equations:"
203	    };
204	    let eqs = merged_equations(sig);
205	    let mut elems = vec![text(header)];
206	    for d in punctuate(&char(','), eqs.iter().map(equation_doc).collect()) {
207	        elems.push(nest(4, &d));
208	    }
209	    sep(elems)
210	}
211	
212	/// `sep [lhs, nest (-2) ("= " <> rhs)]`: one line `lhs = rhs`; an overlong
213	/// equation drops `= rhs` to (equation indent − 2) (probe:e_long).
214	fn equation_doc(eq: &Equation) -> Doc {
215	    sep(vec![
216	        term::doc(&eq.lhs),
217	        nest(-2, &beside_op(text("= "), term::doc(&eq.rhs))),
218	    ])
219	}
220	
221	/// One-line text of an equation — the exact-dedup key (probe:e_dup pins
222	/// exact-dedup; probe:e_adedup pins that alpha-variants are kept).
223	fn equation_key(eq: &Equation) -> String {
224	    render_with(isize::MAX / 2, isize::MAX / 2, &equation_doc(eq))
225	}
226	
227	/// Base + builtin-expansion + user equations, deduped exactly and sorted by
228	/// the structural (lhs, rhs) order — see [`equation_cmp`]. The sort is
229	/// independent of declaration order (probes p_eqA/p_eqB, p_eqF/p_eqF2) and is
230	/// NOT byte order of the rendered text (target:contract checkpcs pair,
231	/// target:mesh get_b1/get_b2 groups, probes p_eqC/p_eqC2).
232	fn merged_equations(sig: &Signature) -> Vec<Equation> {
233	    let mut eqs = base_equations();
234	    for b in &sig.builtins {
235	        eqs.extend(builtin_equations(b));
236	    }
237	    eqs.extend(sig.equations.iter().cloned());
238	    let mut keyed: Vec<(String, Equation)> =
239	        eqs.into_iter().map(|e| (equation_key(&e), e)).collect();
240	    keyed.sort_by(|a, b| equation_cmp(&a.1, &b.1));
241	    keyed.dedup_by(|a, b| a.0 == b.0);
242	    keyed.into_iter().map(|(_, e)| e).collect()
243	}
244	
245	// ── equation ordering (structural term order) ───────────────────────────────
246	
247	/// Equations compare lexicographically on (lhs, rhs): rhs participates and
248	/// breaks lhs ties (probes p_eqF/p_eqF2 — identical lhs, `= x` before `= y`
249	/// regardless of declaration order).
250	fn equation_cmp(a: &Equation, b: &Equation) -> Ordering {
251	    term_cmp(&a.lhs, &b.lhs).then_with(|| term_cmp(&a.rhs, &b.rhs))
252	}
253	
254	/// A term as the comparison model sees it: either a real AST node or the
255	/// tail of a tuple (tuples compare as RIGHT-NESTED binary `pair`
256	/// applications — probe:p_eqI: `<x, zz>` sorts before `<x, b, c>` because
257	/// the binary view compares `zz` (a variable) against `pair(b, c)`; the
258	/// flattened elementwise view would order the other way).
259	#[derive(Clone, Copy)]
260	enum CmpView<'a> {
261	    Node(&'a Term),
262	    PairTail(&'a [Term]),
263	}
264	
265	/// Structural term order pinned by the equations block (probes p_eqA–p_eqI,
266	/// targets contract/mesh):
267	///   * variables sort below ALL applications, whatever the names
268	///     (p_eqC/p_eqC2: `zzz` before nullary `a0`; contract: `xpk` before
269	///     `pk(xsk)`; mesh: `cnf` before `aes_cmac(…)`);
270	///   * variable vs variable: name bytes, then index (p_eqD byte order not
271	///     shortlex: `azz` < `b`; p_eqH: `x` < `x.1`);
272	///   * application vs application: head name bytes FIRST (p_eqG refutes
273	///     arity-first: `pair` < `z1` despite arity 2 vs 1), then arguments
274	///     left-to-right (contract checkpcs decided at argument 2);
275	///   * tuples take the head name `pair` (p_eqE: `g(…)` < `<x, y>`; p_eqG:
276	///     `<x, y>` < `z1(…)`) and right-nested binary arguments (p_eqI).
277	/// Classes that cannot appear in an equations block (literals, exp/AC
278	/// operators, diff, pattern-match) are UNOBSERVABLE here; they are ranked
279	/// with the applications under their rendered head spelling (flagged in
280	/// BEHAVIOR.md, to be confirmed by the corpus gate if they ever occur).
281	fn term_cmp(a: &Term, b: &Term) -> Ordering {
282	    view_cmp(CmpView::Node(a), CmpView::Node(b))
283	}
284	
285	fn view_cmp(a: CmpView, b: CmpView) -> Ordering {
286	    // Resolve single-element tails and tuple nodes to a common shape.
287	    let a = resolve(a);
288	    let b = resolve(b);
289	    match (var_of(a), var_of(b)) {
290	        (Some(va), Some(vb)) => {
291	            va.name.cmp(&vb.name).then(va.idx.cmp(&vb.idx))
292	        }
293	        (Some(_), None) => Ordering::Less,
294	        (None, Some(_)) => Ordering::Greater,
295	        (None, None) => {
296	            let (na, aa) = app_view(a);
297	            let (nb, ab) = app_view(b);
298	            na.cmp(&nb).then_with(|| args_cmp(&aa, &ab))
299	        }
300	    }
301	}
302	
303	/// Collapse a one-element pair tail to its element (a tuple `<a, b, c>` is
304	/// `pair(a, pair(b, c))` — the final tail is just the last element).
305	fn resolve(v: CmpView) -> CmpView {
306	    match v {
307	        CmpView::PairTail(elems) if elems.len() == 1 => {
308	            resolve(CmpView::Node(&elems[0]))
309	        }
310	        CmpView::Node(Term::Pair(elems)) => resolve(CmpView::PairTail(elems)),
311	        other => other,
312	    }
313	}
314	
315	fn var_of<'a>(v: CmpView<'a>) -> Option<&'a VarSpec> {
316	    match v {
317	        CmpView::Node(Term::Var(spec)) => Some(spec),
318	        _ => None,
319	    }
320	}
321	
322	/// Head spelling + argument views of an application-like term.
323	fn app_view(v: CmpView) -> (String, Vec<CmpView>) {
324	    match v {
325	        CmpView::PairTail(elems) => (
326	            "pair".into(),
327	            vec![CmpView::Node(&elems[0]), CmpView::PairTail(&elems[1..])],
328	        ),
329	        CmpView::Node(t) => match t {
330	            Term::App(f, args) => {
331	                (f.clone(), args.iter().map(CmpView::Node).collect())
332	            }
333	            Term::AlgApp(f, x, y) => {
334	                (f.clone(), vec![CmpView::Node(x), CmpView::Node(y)])
335	            }
336	            Term::Diff(l, r) => {
337	                ("diff".into(), vec![CmpView::Node(l), CmpView::Node(r)])
338	            }
339	            // UNOBSERVABLE in equations — rendered-spelling rank (BEHAVIOR.md).
340	            Term::BinOp(op, x, y) => {
341	                let name = match op {
342	                    crate::ast::BinOp::Exp => "^",
343	                    crate::ast::BinOp::Mult => "*",
344	                    crate::ast::BinOp::Union => "++",
345	                    crate::ast::BinOp::Xor => "\u{2295}",
346	                    crate::ast::BinOp::NatPlus => "%+",
347	                };
348	                (name.into(), vec![CmpView::Node(x), CmpView::Node(y)])
349	            }
350	            Term::PatMatch(inner) => ("=".into(), vec![CmpView::Node(inner)]),
351	            other => (crate::term::render(other), Vec::new()),
352	        },
353	    }
354	}
355	
356	fn args_cmp(a: &[CmpView], b: &[CmpView]) -> Ordering {
357	    for (x, y) in a.iter().zip(b.iter()) {
358	        let ord = view_cmp(*x, *y);
359	        if ord != Ordering::Equal {
360	            return ord;
361	        }
362	    }
363	    a.len().cmp(&b.len())
364	}
365	
366	/// `x.<i>` — the variable spelling in builtin-induced equations
367	/// (probe:b_none and every builtin expansion probe).
368	fn xv(i: u64) -> Term {
369	    Term::Var(VarSpec {
370	        name: "x".into(),
371	        idx: i,
372	        sort: SortHint::Untagged,
373	        typ: None,
374	    })
375	}
376	
377	fn app(f: &str, args: Vec<Term>) -> Term {
378	    Term::App(f.into(), args)
379	}
380	
381	fn eq(lhs: Term, rhs: Term) -> Equation {
382	    Equation { lhs, rhs }
383	}
384	
385	/// `fst(<x.1, x.2>) = x.1`, `snd(<x.1, x.2>) = x.2` (probe:b_none).
386	fn base_equations() -> Vec<Equation> {
387	    vec![
388	        eq(app("fst", vec![Term::Pair(vec![xv(1), xv(2)])]), xv(1)),
389	        eq(app("snd", vec![Term::Pair(vec![xv(1), xv(2)])]), xv(2)),
390	    ]
391	}
392	
393	/// Equations induced by one declared builtin (probes:b_*).
394	fn builtin_equations(name: &str) -> Vec<Equation> {
395	    match name {
396	        // adec(aenc(x.1, pk(x.2)), x.2) = x.1
397	        "asymmetric-encryption" | "dest-asymmetric-encryption" => vec![eq(
398	            app(
399	                "adec",
400	                vec![
401	                    app("aenc", vec![xv(1), app("pk", vec![xv(2)])]),
402	                    xv(2),
403	                ],
404	            ),
405	            xv(1),
406	        )],
407	        // verify(sign(x.1, x.2), x.1, pk(x.2)) = true
408	        "signing" | "dest-signing" => vec![eq(
409	            app(
410	                "verify",
411	                vec![
412	                    app("sign", vec![xv(1), xv(2)]),
413	                    xv(1),
414	                    app("pk", vec![xv(2)]),
415	                ],
416	            ),
417	            app("true", vec![]),
418	        )],
419	        // sdec(senc(x.1, x.2), x.2) = x.1
420	        "symmetric-encryption" | "dest-symmetric-encryption" => vec![eq(
421	            app(
422	                "sdec",
423	                vec![app("senc", vec![xv(1), xv(2)]), xv(2)],
424	            ),
425	            xv(1),
426	        )],
427	        // getMessage(revealSign(x.1, x.2)) = x.1
428	        // revealVerify(revealSign(x.1, x.2), x.1, pk(x.2)) = true
429	        "revealing-signing" => vec![
430	            eq(
431	                app("getMessage", vec![app("revealSign", vec![xv(1), xv(2)])]),
432	                xv(1),
433	            ),
434	            eq(
435	                app(
436	                    "revealVerify",
437	                    vec![
438	                        app("revealSign", vec![xv(1), xv(2)]),
439	                        xv(1),
440	                        app("pk", vec![xv(2)]),
441	                    ],
442	                ),
443	                app("true", vec![]),
444	            ),
