58	/// The first rule block of a one-rule probe capture: `rule …` through the
59	/// trailing variants comment. `None` when the capture dir is gone.
60	fn probe_block(basename: &str) -> Option<String> {
61	    let cap = std::fs::read_to_string(format!("../../round2/targets/{basename}")).ok()?;
62	    let lines: Vec<&str> = cap.lines().collect();
63	    let start = lines.iter().position(|l| l.starts_with("rule "))?;
64	    let end = start
65	        + lines[start..]
66	            .iter()
67	            .position(|l| {
68	                let t = l.trim();
69	                t == "/* has exactly the trivial AC variant */" || t == "*/"
70	            })
71	            .expect("no variants comment end");
72	    Some(lines[start..=end].join("\n"))
73	}
