77	// `<'lbl', aa, bb, cccccccc, dd>`) sits on the second line, so `macf`'s own
78	// `)` attaches to that tuple (`…dd>)`), making the ENCLOSING tuple multi-line.
79	fn six_tuple() -> Term {
80	    pair(vec![msg("aa"), msg("bb"), msg("cc"), msg("dd"), msg("ee"), msg("ff")])
