83	    app(
84	        "macf",
85	        vec![
86	            app("firstf", vec![app("hashf", vec![six_tuple()])]),
87	            pair(vec![pubc("lbl"), msg("aa"), msg("bb"), msg("cccccccc"), msg("dd")]),
88	        ],
