251	    // render on a SMALL 2 MB stack — far under the production 8 MB — proving
252	    // the iterative Doc build / render / drop, not a wide-stack workaround.
253	    std::thread::Builder::new()
254	        .stack_size(2 * 1024 * 1024)
255	        .spawn(|| {
256	            let base = erule(
257	                "Big",
258	                vec![fact("Fr", vec![var("a", 0, SortHint::Fresh)])],
259	                vec![],
