266	                        (var("a", 0, SortHint::Fresh), var("a", 4, SortHint::Fresh)),
267	                        (var("b", 0, SortHint::Fresh), var("b", 4, SortHint::Fresh)),
268	                    ]
269	                })
270	                .collect();
271	            let v = AcVariants { ac_rule: ac, substitutions: groups };
272	            let out = render_rule(&base, Some(&v));
273	            // Complete render: opens and closes the comment, all groups present.
274	            assert!(out.starts_with("rule (modulo E) Big:"));
275	            assert!(out.trim_end().ends_with("*/"));
276	            assert!(out.contains("12000. "));
277	        })
278	        .unwrap()
279	        .join()
280	        .unwrap();
