732	    /// One operand-position formula unit.
733	    fn funit(&mut self) -> Formula {
734	        self.ws();
735	        if self.eat("\u{22a4}") {
736	            return Formula::True;
737	        }
738	        if self.eat("\u{22a5}") {
739	            return Formula::False;
740	        }
741	        if self.eat("\u{ac}") {
742	            self.expect("(");
743	            let f = self.formula();
744	            self.expect(")");
745	            return Formula::Not(Box::new(f));
746	        }
747	        if self.rest().starts_with('\u{2200}') {
748	            return self.quantifier("\u{2200}");
749	        }
750	        if self.rest().starts_with('\u{2203}') {
751	            return self.quantifier("\u{2203}");
752	        }
753	        if self.rest().starts_with('(') {
754	            // Ambiguity: `(` opens either a formula group or a
755	            // self-parenthesized AC term (`(x++z) = y`). A formula group is
756	            // followed by a connective or a closer; a term paren is followed
757	            // by a relation glyph. Decide by matching the paren.
758	            if !self.paren_is_term() {
759	                self.pos += 1;
760	                let f = self.formula();
761	                self.expect(")");
762	                return f;
763	            }
764	        }
765	        self.formula_atom()
766	    }
