816	    fn formula_atom(&mut self) -> Formula {
817	        self.ws();
818	        if self.rest().starts_with("last(") {
819	            self.pos += "last(".len();
820	            let t = self.term();
821	            self.expect(")");
822	            return Formula::Atom(Atom::Last(t));
823	        }
824	        if self.rest().starts_with('!') {
825	            let f = self.fact();
826	            self.expect("@");
827	            let tp = self.term();
828	            return Formula::Atom(Atom::Action(f, tp));
829	        }
830	        // Nullary fact `Name( )` cannot be parsed as a term; detect the
831	        // `ident( )` shape up front.
832	        let save = self.pos;
833	        let mut is_nullary_fact = false;
834	        if self.rest().chars().next().is_some_and(|c| c.is_ascii_alphanumeric() || c == '_') {
835	            let _ = self.ident();
836	            if self.starts("(") {
837	                self.pos += 1;
838	                if self.starts(")") {
839	                    is_nullary_fact = true;
840	                }
841	            }
842	        }
843	        self.pos = save;
844	        if is_nullary_fact {
845	            let f = self.fact();
846	            self.expect("@");
847	            let tp = self.term();
848	            return Formula::Atom(Atom::Action(f, tp));
849	        }
850	        let t = self.term();
851	        self.ws();
852	        if self.eat("@") {
853	            let (name, args) = match t {
854	                Term::App(name, args) => (name, args),
855	                Term::Var(v) => {
856	                    assert_eq!(v.idx, 0, "action fact head with index");
857	                    (v.name, vec![])
858	                }
859	                other => panic!("action atom on non-fact term {other:?}"),
860	            };
861	            let tp = self.term();
862	            return Formula::Atom(Atom::Action(
863	                Fact {
864	                    persistent: false,
865	                    name,
866	                    args,
867	                    annotations: vec![],
868	                },
869	                tp,
870	            ));
871	        }
872	        if self.eat("=") {
873	            let r = self.term();
874	            return Formula::Atom(Atom::Eq(t, r));
875	        }
876	        if self.eat("\u{228f}") {
877	            let r = self.term();
878	            return Formula::Atom(Atom::Subterm(t, r));
879	        }
880	        if self.eat("<") {
881	            let r = self.term();
882	            return Formula::Atom(Atom::Less(t, r));
883	        }
884	        panic!(
885	            "relation glyph expected at …{:?}",
886	            &self.rest()[..self.rest().len().min(60)]
887	        );
888	    }
