928	/// Slice a capture into its restriction and lemma blocks (verbatim lines).
929	fn item_blocks(capture: &str) -> (Vec<String>, Vec<String>) {
930	    let lines: Vec<&str> = capture.lines().collect();
931	    let mut restrictions = Vec::new();
932	    let mut lemmas = Vec::new();
933	    let mut i = 0;
934	    while i < lines.len() {
935	        if lines[i].starts_with("restriction ") {
936	            let start = i;
937	            while lines[i] != "  */" {
938	                i += 1;
939	            }
940	            restrictions.push(lines[start..=i].join("\n"));
941	        } else if lines[i].starts_with("lemma ") {
942	            let start = i;
943	            // Through the guarded comment's closing `*/` at column 0.
944	            while lines[i] != "*/" {
945	                i += 1;
946	            }
947	            // Tail: a single `by …` line, or an embedded proof script that
948	            // runs through its column-0 `qed`.
949	            i += 1;
950	            if lines[i].starts_with("by ") {
951	                // single-line tail
952	            } else {
953	                while lines[i] != "qed" {
954	                    i += 1;
955	                }
956	            }
957	            lemmas.push(lines[start..=i].join("\n"));
958	        }
959	        i += 1;
960	    }
961	    (restrictions, lemmas)
962	}
