964	fn parse_restriction(block: &str) -> Restriction {
965	    // Statement part: everything before the blank line ahead of the
966	    // expanded-formula comment.
967	    let stmt_end = block.find("\n\n").expect("restriction comment separator");
968	    let stmt = &block[..stmt_end];
969	    let mut p = P::new(stmt);
970	    p.expect("restriction");
971	    p.ws();
972	    let name: String = p.rest().chars().take_while(|c| *c != ':').collect();
973	    p.pos += name.len();
974	    p.expect(":");
975	    p.expect("\"");
976	    let f = p.formula();
977	    p.expect("\"");
978	    let had_safety = p.eat("// safety formula");
979	    p.ws();
980	    assert!(p.rest().is_empty(), "unparsed statement: {:?}", p.rest());
981	    let r = Restriction { name, formula: f };
982	    // The renderer derives the safety line from the formula; cross-check the
983	    // classification against the capture here so a parity PASS can't hide a
984	    // misclassification compensated elsewhere.
985	    assert_eq!(
986	        pretty_clean::render_restriction(&r).contains("\n  // safety formula"),
987	        had_safety,
988	        "safety classification for {}",
989	        r.name
990	    );
991	    r
992	}
