994	fn parse_lemma(block: &str) -> (Lemma, Option<Guarded>) {
995	    let lines: Vec<&str> = block.lines().collect();
996	    // The guarded comment opens at the first column-0 `/*`.
997	    let open = lines
998	        .iter()
999	        .position(|l| *l == "/*")
1000	        .expect("guarded comment opener");
1001	    let close = open + 1 + lines[open + 1..]
1002	        .iter()
1003	        .position(|l| *l == "*/")
1004	        .expect("guarded comment closer");
1005	    let head = lines[..open].join("\n");
1006	    let mut p = P::new(&head);
1007	    p.expect("lemma");
1008	    p.ws();
1009	    let name: String = p
1010	        .rest()
1011	        .chars()
1012	        .take_while(|c| !c.is_whitespace() && *c != '[' && *c != ':')
1013	        .collect();
1014	    p.pos += name.len();
1015	    p.ws();
1016	    let attributes = if p.eat("[") {
1017	        let a = p.lemma_attrs();
1018	        p.expect("]");
1019	        a
1020	    } else {
1021	        Vec::new()
1022	    };
1023	    p.expect(":");
1024	    let trace_quantifier = if p.eat("all-traces") {
1025	        TraceQuantifier::AllTraces
1026	    } else {
1027	        p.expect("exists-trace");
1028	        TraceQuantifier::ExistsTrace
1029	    };
1030	    p.expect("\"");
1031	    let formula = p.formula();
1032	    p.expect("\"");
1033	    p.ws();
1034	    assert!(p.rest().is_empty(), "unparsed lemma head: {:?}", p.rest());
1035	
1036	    // Guarded comment interior: header line + verbatim content.
1037	    let header = lines[open + 1];
1038	    let content = lines[open + 2..close].join("\n");
1039	    let guarded = if header == "conversion to guarded formula failed:" {
1040	        let stripped: Vec<String> = lines[open + 2..close]
1041	            .iter()
1042	            .map(|l| l.strip_prefix("  ").unwrap_or(l).to_string())
1043	            .collect();
1044	        Guarded::Failed(stripped.join("\n"))
1045	    } else {
1046	        let expected_header = match trace_quantifier {
1047	            TraceQuantifier::AllTraces => "guarded formula characterizing all counter-examples:",
1048	            TraceQuantifier::ExistsTrace => "guarded formula characterizing all satisfying traces:",
1049	        };
1050	        assert_eq!(header, expected_header, "guarded header for {name}");
1051	        Guarded::Formula(content)
1052	    };
1053	
1054	    // Tail: `by sorry` or a verbatim embedded proof.
1055	    let tail = lines[close + 1..].join("\n");
1056	    let proof = if tail == "by sorry" { None } else { Some(tail) };
1057	    (
1058	        Lemma {
1059	            name,
1060	            attributes,
1061	            trace_quantifier,
1062	            formula,
1063	            proof,
1064	        },
1065	        Some(guarded),
1066	    )
1067	}
