861	#[test]
862	fn parity_rule_blocks_match_captures() {
863	    // The curated set now includes the round-4 deep files whose `variants
864	    // (modulo AC)` comments run to ~10 000 lines (C8, BP_IBS_2/3/4). The Doc
865	    // engine's build / render / drop are all iterative (blocker 3 fix), so a
866	    // production-sized 8 MB thread renders them without overflow — proving the
867	    // fix, not papering over it with a 512 MB workaround. Parsing the giant
868	    // comment is likewise iterative (the substitution loop is a `while`).
869	    std::thread::Builder::new()
870	        .stack_size(8 * 1024 * 1024)
871	        .spawn(parity_rule_blocks_impl)
872	        .unwrap()
873	        .join()
874	        .unwrap();
875	}
876	
877	fn parity_rule_blocks_impl() {
878	    // Sealed-workspace location of the curated round-2 captures; self-skips
879	    // once the crate moves at integration (the corpus gate takes over).
880	    let dir = std::path::Path::new("../../round2/targets");
881	    if !dir.is_dir() {
882	        return;
883	    }
884	    let mut checked = 0;
885	    for entry in std::fs::read_dir(dir).unwrap() {
886	        let path = entry.unwrap().path();
887	        if path.extension().and_then(|e| e.to_str()) != Some("txt") {
